const raw = $input.first().json['LinkedIn Company URLs'] || '';
return raw.split('\n').map(u => u.trim()).filter(u => u)
  .map(linkedin_url => ({ json: { linkedin_url } }));

const response  = $input.first().json;
const data      = response.result || response;
const input_url = $('One URL at a Time').first().json.linkedin_url;

if (!data || response.status === 'error')
  return [{ json: { input_url, status: 'error' } }];

return [{ json: {
  input_url,
  name:          data.name           || '',
  tagline:       data.tagline        || '',
  industry:      data.industry       || '',
  company_size:  data.company_size   || data.companySize    || '',
  follower_count:data.followerCount  || data.follower_count || '',
  city:          data.city           || '',
  country:       data.country        || '',
  founded_on:    data.foundedOn      || data.founded_on     || '',
  website:       data.website        || '',
  company_email: data.company_email  || data.companyEmail   || '',
  company_phone: data.company_phone  || data.companyPhone   || '',
  description:   (data.company_description || data.description || '').substring(0, 500),
  linkedin_url:  data.linkedinUrl    || input_url
}}];
